import { useState } from "react";
import Join from "./Join";
import Room from "./Room";
import Results from "./Results";
import Login from "./Login";

function App() {
  const [room, setRoom] = useState("");
  const [userName, setUserName] = useState("");
  const [role, setRole] = useState("");
  const [userId, setUserId] = useState(null);

  const [page, setPage] = useState("login");

  return (
    <div>
      {page !== "login" && (
        <>
          <button onClick={() => setPage("join")}>Главная</button>
          <button onClick={() => setPage("results")}>История</button>
        </>
      )}

      {page === "login" && (
        <Login
          setPage={setPage}
          setUserId={setUserId}
          setRole={setRole}
        />
      )}

      {page === "join" && !room && (
        <Join setRoom={setRoom} setName={setUserName} />
      )}

      {page === "join" && room && (
        <Room
          room={room}
          userName={userName}
          role={role}
        />
      )}

      {page === "results" && <Results userId={userId} />}
    </div>
  );
}

export default App;
